question:
\begin{itemize}
\item[(i)] $I \in \MM$, where $I$ is the $n \times n$ identity matrix;

\item[(ii)] if $A \in \MM$ and $B \in \MM$, then either $AB \in \MM$ or
$-AB \in \MM$, but not both;

\item[(iii)] if $A \in \MM$ and $B \in \MM$, then either $AB = BA$ or
$AB = -BA$;

\item[(iv)] if $A \in \MM$ and $A \neq I$, there is at least one $B \in
\MM$ such that $AB = - BA$.
\end{itemize}
Prove that $\MM$ contains at most $n^2$ matrices.
\end{itemize}
\end{document}

descriptive_long.question:
\begin{itemize}
\item[(i)] $identy \in matrixset$, where $identy$ is the $dimsize \times dimsize$ identity matrix;

\item[(ii)] if $matrixa \in matrixset$ and $matrixb \in matrixset$, then either $matrixa matrixb \in matrixset$ or
$-matrixa matrixb \in matrixset$, but not both;

\item[(iii)] if $matrixa \in matrixset$ and $matrixb \in matrixset$, then either $matrixa matrixb = matrixb matrixa$ or
$matrixa matrixb = -matrixb matrixa$;

\item[(iv)] if $matrixa \in matrixset$ and $matrixa \neq identy$, there is at least one $matrixb \in
matrixset$ such that $matrixa matrixb = - matrixb matrixa$.
\end{itemize}
Prove that $matrixset$ contains at most $dimsize^{2}$ matrices.

